    vcs {
        root(AbsoluteId("Metalama_Metalama20251_MetalamaConsolidated"))
        root(AbsoluteId("Metalama_Metalama20251_MetalamaCompiler"),
          """+:. => source-dependencies/Metalama.Compiler""")
        root(AbsoluteId("Metalama_Metalama20251_Metalama"),
          """+:. => source-dependencies/Metalama""")
        root(AbsoluteId("Metalama_Metalama20251_MetalamaCommunity"),
          """+:. => source-dependencies/Metalama.Community""")
        root(AbsoluteId("Metalama_Metalama20251_MetalamaPremium"),
          """+:. => source-dependencies/Metalama.Premium""")
        root(AbsoluteId("Metalama_Metalama20251_MetalamaSamples"),
          """+:. => source-dependencies/Metalama.Samples""")
        root(AbsoluteId("Metalama_Metalama20251_MetalamaDocumentation"),
          """+:. => source-dependencies/Metalama.Documentation""")
        root(AbsoluteId("Metalama_Metalama20251_MetalamaVsx"),
          """+:. => source-dependencies/Metalama.Vsx""")
        root(AbsoluteId("Metalama_Metalama20251_MetalamaTestsNopCommerce"),
          """+:. => source-dependencies/Metalama.Tests.NopCommerce""")
     checkoutMode = CheckoutMode.ON_AGENT
    }

    steps {
        powerShell {
            name = "Clean NuGet cache of produced and dependency packages"
            id = "CleanNuGetCache"
            edition = PowerShellStep.Edition.Core
            scriptMode = script {
                content = "${'$'}nugetPackages = if ( ${'$'}env:NUGET_PACKAGES ) { ${'$'}env:NUGET_PACKAGES } else { Join-Path ${'$'}HOME '.nuget' 'packages' }; ${'$'}removedDirs = 0; ${'$'}removedFiles = 0; if ( Test-Path -LiteralPath ${'$'}nugetPackages ) { foreach ( ${'$'}pattern in @('flashtrace*', 'metalama.backstage*', 'metalama.community', 'metalama.community.*', 'metalama.compiler', 'metalama.compiler.*', 'metalama.consolidated', 'metalama.consolidated.*', 'metalama.documentation', 'metalama.documentation.*', 'metalama.documentation.quickstart', 'metalama.extensions.architecture', 'metalama.extensions.codefixes', 'metalama.extensions.codefixes.redist', 'metalama.extensions.dependencyinjection', 'metalama.extensions.dependencyinjection.servicelocator', 'metalama.extensions.metrics', 'metalama.extensions.multicast', 'metalama.extensions.validation', 'metalama.extensions.validation.redist', 'metalama.framework*', 'metalama.licensing', 'metalama.linqpad', 'metalama.migration', 'metalama.patterns.caching', 'metalama.patterns.caching.aspects', 'metalama.patterns.caching.backend', 'metalama.patterns.caching.backends.azure', 'metalama.patterns.caching.backends.redis', 'metalama.patterns.caching.testhelpers', 'metalama.patterns.contracts', 'metalama.patterns.immutability', 'metalama.patterns.memoization', 'metalama.patterns.observability', 'metalama.patterns.testhelpers', 'metalama.patterns.wpf', 'metalama.repacked', 'metalama.testing.*', 'metalama.tool', 'postsharp', 'postsharp.compiler.*', 'postsharp.engineering', 'postsharp.engineering.*', 'postsharp.patterns.*', 'postsharp.redist', 'postsharp.settings.*') ) { Get-ChildItem -LiteralPath ${'$'}nugetPackages -Directory -Filter ${'$'}pattern -ErrorAction SilentlyContinue | ForEach-Object { ${'$'}files = @( Get-ChildItem -LiteralPath ${'$'}_.FullName -Recurse -File -ErrorAction SilentlyContinue ).Count; Write-Host \"Removing NuGet cache directory: ${'$'}(${'$'}_.FullName) (${'$'}files file(s))\"; Remove-Item -LiteralPath ${'$'}_.FullName -Recurse -Force -ErrorAction SilentlyContinue; if ( -not ( Test-Path -LiteralPath ${'$'}_.FullName ) ) { ${'$'}removedDirs++; ${'$'}removedFiles += ${'$'}files } } } Write-Host \"Removed ${'$'}removedDirs package directory(ies) and ${'$'}removedFiles file(s) from the NuGet cache.\"; } else { Write-Host \"NuGet packages folder not found: ${'$'}nugetPackages\" }"
            }
            noProfile = false
        }
        powerShell {
            name = "Prepare Docker image metalamaconsolidated-2025.1"
            id = "PrepareImage"
            edition = PowerShellStep.Edition.Core
            scriptMode = file {
                path = "DockerBuild.ps1"
            }
            noProfile = false
            scriptArgs = "-BuildImage -ImageName metalamaconsolidated-2025.1 "
        }
        powerShell {
            name = "Execute Orchestrator.ps1"
            id = "Exec"
            edition = PowerShellStep.Edition.Core
            scriptMode = file {
                path = "DockerBuild.ps1"
            }
            noProfile = false
            scriptArgs = "-Script Orchestrator.ps1 -ImageName metalamaconsolidated-2025.1 -NoBuildImage -Label %system.teamcity.buildType.id%_%build.number% postpublish %Exec.Arguments%"
        }
        powerShell {
            name = "Cleanup Docker containers"
            id = "DockerCleanup"
            executionMode = BuildStep.ExecutionMode.ALWAYS
            edition = PowerShellStep.Edition.Core
            scriptMode = script {
                content = "${'$'}label = \"%system.teamcity.buildType.id%_%build.number%\"; ${'$'}ids = docker ps -a -q --filter \"label=postsharp.build=${'$'}label\"; if (${'$'}ids) { docker rm -f ${'$'}ids 2>&1 | Out-Null }"
            }
            noProfile = false
        }
    }

    requirements {
        matches("teamcity.agent.jvm.os.family", "Windows")
        matches("teamcity.agent.jvm.os.arch", "amd64")
        equals("env.BuildAgentType", "docker-win-x64-md")
    }

    features {
        swabra {
            filesCleanup = Swabra.FilesCleanup.BEFORE_BUILD
            lockingProcesses = Swabra.LockingProcessPolicy.KILL
            verbose = true
        }
    }

})

